<?php
declare(strict_types=1);
require_once dirname(__DIR__) . '/includes/cms.php';
require_once dirname(__DIR__,3).'/includes/noticias.php';
$pdo=obtenerConexion();$id=cmsId($_GET['id']??$_POST['id']??0);
$f=['id'=>0,'titulo'=>'','slug'=>'','resumen'=>'','contenido'=>'','imagen_portada'=>'','fecha_publicacion'=>date('Y-m-d\TH:i'),'autor'=>'','estado'=>'borrador','destacado'=>0,'activo'=>1];
if($id){$q=$pdo->prepare('SELECT * FROM noticias WHERE id=:id AND deleted_at IS NULL');$q->execute(['id'=>$id]);$f=$q->fetch()?:$f;if(!$f['id']){cmsFlash('error','La noticia no existe.');header('Location:index.php');exit;}$f['fecha_publicacion']=$f['fecha_publicacion']?date('Y-m-d\TH:i',strtotime($f['fecha_publicacion'])):'';}
$errores=[];
if(($_SERVER['REQUEST_METHOD']??'GET')==='POST'){
    if(!validarTokenCsrf(isset($_POST['csrf_token'])?(string)$_POST['csrf_token']:null))$errores[]='La solicitud expiró.';
    $titulo=trim((string)($_POST['titulo']??''));$slug=normalizarSlugNoticia((string)($_POST['slug']??$titulo));$resumen=trim((string)($_POST['resumen']??''));$contenido=trim((string)($_POST['contenido']??''));$autor=trim((string)($_POST['autor']??''));$fechaTexto=trim((string)($_POST['fecha_publicacion']??''));$estado=in_array((string)($_POST['estado']??''),['borrador','publicado'],true)?(string)$_POST['estado']:'borrador';$destacado=isset($_POST['destacado'])?1:0;$activo=isset($_POST['activo'])?1:0;
    $fecha=null;if($fechaTexto!==''){$dt=DateTimeImmutable::createFromFormat('!Y-m-d\TH:i',$fechaTexto);if(!$dt||$dt->format('Y-m-d\TH:i')!==$fechaTexto)$errores[]='La fecha de publicación no es válida.';else$fecha=$dt->format('Y-m-d H:i:s');}
    if($titulo===''||mb_strlen($titulo)>190)$errores[]='El título es obligatorio y admite hasta 190 caracteres.';
    if(!slugNoticiaValido($slug))$errores[]='El slug debe contener únicamente letras minúsculas, números y guiones.';
    if($resumen===''||mb_strlen($resumen)>500)$errores[]='El resumen es obligatorio y admite hasta 500 caracteres.';
    if($contenido===''||mb_strlen($contenido)>100000)$errores[]='El contenido completo es obligatorio y no debe superar 100000 caracteres.';
    if(mb_strlen($autor)>180)$errores[]='El autor no debe superar 180 caracteres.';
    if($estado==='publicado'&&$fecha===null)$errores[]='Una noticia publicada necesita fecha de publicación.';
    $imagen=(string)$f['imagen_portada'];$nueva=null;
    if(!$errores){try{$nueva=cmsSubirImagen('imagen_portada');if($nueva)$imagen=$nueva;}catch(RuntimeException$e){$errores[]=$e->getMessage();}}
    if(!$errores){try{$pdo->beginTransaction();$datos=['titulo'=>$titulo,'slug'=>$slug,'resumen'=>$resumen,'contenido'=>$contenido,'imagen'=>$imagen?:null,'fecha'=>$fecha,'autor'=>$autor?:null,'estado'=>$estado,'destacado'=>$destacado,'activo'=>$activo];if($id){$datos['id']=$id;$q=$pdo->prepare('UPDATE noticias SET titulo=:titulo,slug=:slug,resumen=:resumen,contenido=:contenido,imagen_portada=:imagen,fecha_publicacion=:fecha,autor=:autor,estado=:estado,destacado=:destacado,activo=:activo WHERE id=:id AND deleted_at IS NULL');}else$q=$pdo->prepare('INSERT INTO noticias(titulo,slug,resumen,contenido,imagen_portada,fecha_publicacion,autor,estado,destacado,activo) VALUES(:titulo,:slug,:resumen,:contenido,:imagen,:fecha,:autor,:estado,:destacado,:activo)');$q->execute($datos);$noticiaId=$id?:((int)$pdo->lastInsertId());registrarAuditoria(['actor_user_id'=>(int)$_SESSION['usuario_id'],'event_type'=>$id?'news.updated':'news.created','module'=>'news','entity_type'=>'news','entity_id'=>$noticiaId,'action'=>$id?'update':'create','result'=>'success','description'=>$id?'Se actualizó una noticia.':'Se creó una noticia.'],$pdo);$pdo->commit();if($id&&$imagen!==$f['imagen_portada'])cmsEliminarImagenSiNoSeUsa($f['imagen_portada']);cmsFlash('exito','Noticia guardada correctamente.');header('Location:index.php');exit;}catch(Throwable$e){if($pdo->inTransaction())$pdo->rollBack();if($nueva)cmsEliminarImagenSiNoSeUsa($nueva);error_log('Guardar noticia: '.$e->getMessage());$errores[]=$e instanceof PDOException&&(string)$e->getCode()==='23000'?'El slug ya pertenece a otra noticia.':'No fue posible guardar la noticia.';}}
    $f=array_merge($f,['titulo'=>$titulo,'slug'=>$slug,'resumen'=>$resumen,'contenido'=>$contenido,'imagen_portada'=>$imagen,'fecha_publicacion'=>$fechaTexto,'autor'=>$autor,'estado'=>$estado,'destacado'=>$destacado,'activo'=>$activo]);
}
cmsCabecera($id?'Editar noticia':'Nueva noticia','noticias/editar.php','Administra la información editorial y su estado de publicación.');
?>
<?php foreach($errores as$error):?><div class="alert alert-danger"><?=atenea_e($error)?></div><?php endforeach;?>
<form method="post" enctype="multipart/form-data" class="card card-rounded"><div class="card-body row g-3"><input type="hidden" name="csrf_token" value="<?=atenea_e(obtenerTokenCsrf())?>"><input type="hidden" name="id" value="<?=$id?>"><div class="col-md-8"><label class="form-label" for="titulo">Título *</label><input class="form-control" id="titulo" name="titulo" maxlength="190" value="<?=atenea_e($f['titulo'])?>" required></div><div class="col-md-4"><label class="form-label" for="slug">Slug</label><input class="form-control" id="slug" name="slug" maxlength="190" pattern="[a-z0-9]+(?:-[a-z0-9]+)*" value="<?=atenea_e($f['slug'])?>" placeholder="se-genera-del-titulo"></div><div class="col-12"><label class="form-label" for="resumen">Resumen *</label><textarea class="form-control" id="resumen" name="resumen" maxlength="500" rows="3" required><?=atenea_e($f['resumen'])?></textarea><div class="form-text">Se muestra en las tarjetas del index y del listado.</div></div><div class="col-12"><label class="form-label" for="contenido">Contenido completo *</label><textarea class="form-control" id="contenido" name="contenido" maxlength="100000" rows="12" required><?=atenea_e($f['contenido'])?></textarea></div><div class="col-md-6"><label class="form-label" for="autor">Autor</label><input class="form-control" id="autor" name="autor" maxlength="180" value="<?=atenea_e((string)$f['autor'])?>"></div><div class="col-md-6"><label class="form-label" for="fecha_publicacion">Fecha de publicación</label><input class="form-control" id="fecha_publicacion" type="datetime-local" name="fecha_publicacion" value="<?=atenea_e((string)$f['fecha_publicacion'])?>"></div><div class="col-md-6"><label class="form-label" for="imagen_portada">Imagen de portada JPG, PNG o WEBP</label><input class="form-control" id="imagen_portada" type="file" name="imagen_portada" accept=".jpg,.jpeg,.png,.webp"><div class="form-text">Máximo 5 MB; el servidor genera un nombre aleatorio.</div></div><div class="col-md-3"><label class="form-label" for="estado">Estado editorial</label><select class="form-select" id="estado" name="estado"><option value="borrador" <?=$f['estado']==='borrador'?'selected':''?>>Borrador</option><option value="publicado" <?=$f['estado']==='publicado'?'selected':''?>>Publicado</option></select></div><div class="col-md-3 d-flex flex-column justify-content-end gap-2"><label><input type="checkbox" name="destacado" <?=$f['destacado']?'checked':''?>> Destacada</label><label><input type="checkbox" name="activo" <?=$f['activo']?'checked':''?>> Activa</label></div><?php if($f['imagen_portada']):?><div class="col-12"><img class="preview-img" src="<?=rutaImagenContenido($f['imagen_portada'])?>" alt="Portada actual"></div><?php endif;?><div class="col-12"><a class="btn btn-light" href="index.php">Volver</a><?php if($id):?> <a class="btn btn-outline-info" target="_blank" rel="noopener" href="preview.php?id=<?=$id?>">Previsualizar</a><?php endif;?> <button class="btn btn-primary text-white">Guardar noticia</button></div></div></form>
<script>const title=document.getElementById('titulo'),slug=document.getElementById('slug');let slugEdited=slug.value!=='';slug.addEventListener('input',()=>slugEdited=slug.value!=='');title.addEventListener('input',()=>{if(!slugEdited)slug.value=title.value.normalize('NFD').replace(/[\u0300-\u036f]/g,'').toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/^-|-$/g,'').slice(0,190);});</script>
